}

BOSNode *bostree_next_node(BOSNode *node) {
        if(node->right_child_node) {
                node = node->right_child_node;
                while(node->left_child_node) {
                        node = node->left_child_node;
                }
                return node;
        }
        else if(node->parent_node) {
