    pub right_child_node: Option<Rc<RefCell<BOSNode>>>,
    pub parent_node: Option<Weak<RefCell<BOSNode>>>,
    pub key: String,
    pub data: Option<String>,
    pub weak_ref_count: u8,
    pub weak_ref_node_valid: u8,
}

pub type BOSTreeCmpFunction = fn(&str, &str) -> i32;
pub type BOSTreeFreeFunction = fn(&Rc<RefCell<BOSNode>>);

fn imax(i1: i32, i2: i32) -> i32 {
    if i1 > i2 { i1 } else { i2 }
}

fn bostree_balance(node: &BOSNode) -> i32 {
    let left_depth = node.left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let right_depth = node.right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    right_depth as i32 - left_depth as i32
}

fn update_depth(node: &Rc<RefCell<BOSNode>>) {
    let left_depth = node.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    let right_depth = node.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
    node.borrow_mut().depth = max(left_depth, right_depth);
}

fn rotate_right(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let l = p.borrow().left_child_node.as_ref().unwrap().clone();

    let p_parent = p.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
    if let Some(ref pp) = p_parent {
        let mut pp_b = pp.borrow_mut();
        if let Some(ref left) = pp_b.left_child_node {
            if Rc::ptr_eq(left, p) {
                pp_b.left_child_node = Some(l.clone());
            } else {
                pp_b.right_child_node = Some(l.clone());
            }
        } else {
            pp_b.right_child_node = Some(l.clone());
        }
    } else {
        tree.root_node = Some(l.clone());
    }

    l.borrow_mut().parent_node = p.borrow().parent_node.clone();

    let l_right = l.borrow().right_child_node.clone();
    p.borrow_mut().left_child_node = l_right.clone();
    p.borrow_mut().left_child_count = l.borrow().right_child_count;
    if let Some(ref lr) = l_right {
        lr.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    update_depth(p);
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));

    l.borrow_mut().right_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&l));
    l.borrow_mut().right_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;
    update_depth(&l);

    l
}

fn rotate_left(tree: &mut BOSTree, p: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let r = p.borrow().right_child_node.as_ref().unwrap().clone();

    let p_parent = p.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
    if let Some(ref pp) = p_parent {
        let mut pp_b = pp.borrow_mut();
        if let Some(ref left) = pp_b.left_child_node {
            if Rc::ptr_eq(left, p) {
                pp_b.left_child_node = Some(r.clone());
            } else {
                pp_b.right_child_node = Some(r.clone());
            }
        } else {
            pp_b.right_child_node = Some(r.clone());
        }
    } else {
        tree.root_node = Some(r.clone());
    }

    r.borrow_mut().parent_node = p.borrow().parent_node.clone();

    let r_left = r.borrow().left_child_node.clone();
    p.borrow_mut().right_child_node = r_left.clone();
    p.borrow_mut().right_child_count = r.borrow().left_child_count;
    if let Some(ref rl) = r_left {
        rl.borrow_mut().parent_node = Some(Rc::downgrade(p));
    }

    update_depth(p);
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));

    r.borrow_mut().left_child_node = Some(p.clone());
    p.borrow_mut().parent_node = Some(Rc::downgrade(&r));
    r.borrow_mut().left_child_count = p.borrow().left_child_count + p.borrow().right_child_count + 1;
    update_depth(&r);

    r
}

impl BOSTree {
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    pub fn bostree_node_count(&self) -> u32 {
        self.root_node.as_ref().map_or(0, |root| {
            let b = root.borrow();
            b.left_child_count + b.right_child_count + 1
        })
    }

    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
        let mut current = self.root_node.clone();
        let mut parent: Option<Rc<RefCell<BOSNode>>> = None;
        let mut go_left = false;

        while let Some(ref node) = current {
            parent = Some(node.clone());
            let cmp = (self.cmp_function)(&key, &node.borrow().key);
            if cmp < 0 {
                node.borrow_mut().left_child_count += 1;
                go_left = true;
                let left = node.borrow().left_child_node.clone();
                current = left;
            } else {
                node.borrow_mut().right_child_count += 1;
                go_left = false;
                let right = node.borrow().right_child_node.clone();
                current = right;
            }
        }

        let new_node = Rc::new(RefCell::new(BOSNode {
            left_child_count: 0,
            right_child_count: 0,
            depth: 0,
            left_child_node: None,
            right_child_node: None,
            parent_node: parent.as_ref().map(|p| Rc::downgrade(p)),
            key,
            data,
            weak_ref_count: 1,
            weak_ref_node_valid: 1,
        }));

        if let Some(ref p) = parent {
            let mut p_b = p.borrow_mut();
            if go_left {
                p_b.left_child_node = Some(new_node.clone());
            } else {
                p_b.right_child_node = Some(new_node.clone());
            }
        } else {
            self.root_node = Some(new_node.clone());
        }

        if let Some(ref p) = parent {
            let has_left = p.borrow().left_child_node.is_some();
            let has_right = p.borrow().right_child_node.is_some();
            if has_left ^ has_right {
                let mut current_node = p.clone();
                current_node.borrow_mut().depth = 1;

                loop {
                    let parent_weak_opt = current_node.borrow().parent_node.clone();
                    let parent_opt = parent_weak_opt.as_ref().and_then(|w| w.upgrade());
                    match parent_opt {
                        Some(parent_node) => {
                            let left_depth = parent_node.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                            let right_depth = parent_node.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                            let max_depth = max(left_depth, right_depth);

                            if parent_node.borrow().depth == max_depth {
                                break;
                            }
                            parent_node.borrow_mut().depth = max_depth;

                            let balance = bostree_balance(&parent_node.borrow());
                            if balance < -1 {
                                let left = parent_node.borrow().left_child_node.as_ref().unwrap().clone();
                                if bostree_balance(&left.borrow()) > 0 {
                                    rotate_left(self, &left);
                                }
                                current_node = rotate_right(self, &parent_node);
                            } else if balance > 1 {
                                let right = parent_node.borrow().right_child_node.as_ref().unwrap().clone();
                                if bostree_balance(&right.borrow()) < 0 {
                                    rotate_right(self, &right);
                                }
                                current_node = rotate_left(self, &parent_node);
                            } else {
                                current_node = parent_node;
                            }
                        }
                        None => break,
                    }
                }
            }
        }

        new_node
    }

    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
        let bubble_up: Option<Rc<RefCell<BOSNode>>>;

        let has_left = node.borrow().left_child_node.is_some();
        let has_right = node.borrow().right_child_node.is_some();

        if has_left && has_right {
            let left_depth = node.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
            let right_depth = node.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);

            let (candidate, lost_child, bubble_start) = if left_depth >= right_depth {
                let mut cand = node.borrow().left_child_node.as_ref().unwrap().clone();
                loop {
                    let has_right = cand.borrow().right_child_node.is_some();
                    if !has_right { break; }
                    cand.borrow_mut().right_child_count -= 1;
                    let right = cand.borrow().right_child_node.as_ref().unwrap().clone();
                    cand = right;
                }
                let lost = cand.borrow().left_child_node.clone();
                let bubble = cand.borrow().parent_node.as_ref().and_then(|w| w.upgrade()).unwrap();
                (cand, lost, bubble)
            } else {
                let mut cand = node.borrow().right_child_node.as_ref().unwrap().clone();
                loop {
                    let has_left = cand.borrow().left_child_node.is_some();
                    if !has_left { break; }
                    cand.borrow_mut().left_child_count -= 1;
                    let left = cand.borrow().left_child_node.as_ref().unwrap().clone();
                    cand = left;
                }
                let lost = cand.borrow().right_child_node.clone();
                let bubble = cand.borrow().parent_node.as_ref().and_then(|w| w.upgrade()).unwrap();
                (cand, lost, bubble)
            };

            {
                let bubble_start_b = bubble_start.borrow();
                if bubble_start_b.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &candidate)) {
                    drop(bubble_start_b);
                    bubble_start.borrow_mut().left_child_node = lost_child.clone();
                } else {
                    drop(bubble_start_b);
                    bubble_start.borrow_mut().right_child_node = lost_child.clone();
                }
            }
            if let Some(ref lost) = lost_child {
                lost.borrow_mut().parent_node = Some(Rc::downgrade(&bubble_start));
            }

            {
                let node_b = node.borrow();
                if let Some(ref parent_weak) = node_b.parent_node {
                    if let Some(parent_node) = parent_weak.upgrade() {
                        let mut parent_b = parent_node.borrow_mut();
                        if parent_b.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, node)) {
                            parent_b.left_child_node = Some(candidate.clone());
                        } else {
                            parent_b.right_child_node = Some(candidate.clone());
                        }
                    }
                } else {
                    self.root_node = Some(candidate.clone());
                }
            }

            candidate.borrow_mut().parent_node = node.borrow().parent_node.clone();
            candidate.borrow_mut().left_child_node = node.borrow().left_child_node.clone();
            candidate.borrow_mut().left_child_count = node.borrow().left_child_count;
            candidate.borrow_mut().right_child_node = node.borrow().right_child_node.clone();
            candidate.borrow_mut().right_child_count = node.borrow().right_child_count;

            if let Some(ref left) = candidate.borrow().left_child_node {
                left.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }
            if let Some(ref right) = candidate.borrow().right_child_node {
                right.borrow_mut().parent_node = Some(Rc::downgrade(&candidate));
            }

            if !Rc::ptr_eq(&bubble_start, node) {
                let mut current = bubble_start;
                loop {
                    update_depth(&current);
                    let balance = bostree_balance(&current.borrow());
                    if balance > 1 {
                        let right = current.borrow().right_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&right.borrow()) < 0 {
                            rotate_right(self, &right);
                        }
                        current = rotate_left(self, &current);
                    } else if balance < -1 {
                        let left = current.borrow().left_child_node.as_ref().unwrap().clone();
                        if bostree_balance(&left.borrow()) > 0 {
                            rotate_left(self, &left);
                        }
                        current = rotate_right(self, &current);
                    }

                    if Rc::ptr_eq(&current, &candidate) { break; }
                    let parent = current.borrow().parent_node.as_ref().and_then(|w| w.upgrade());
                    match parent {
                        Some(p) => current = p,
                        None => break,
                    }
                }
            }

            update_depth(&candidate);
            bubble_up = candidate.borrow().parent_node.as_ref().and_then(|w| w.upgrade());

            if let Some(ref bu) = bubble_up {
                let mut bu_b = bu.borrow_mut();
                if bu_b.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, &candidate)) {
                    bu_b.left_child_count -= 1;
                } else {
                    bu_b.right_child_count -= 1;
                }
            }
        } else {
            let candidate = if has_left {
                node.borrow().left_child_node.clone()
            } else {
                node.borrow().right_child_node.clone()
            };

            let candidate_count = if has_left {
                node.borrow().left_child_count
            } else {
                node.borrow().right_child_count
            };

            if node.borrow().parent_node.is_none() {
                self.root_node = candidate.clone();
                if let Some(ref c) = candidate {
                    c.borrow_mut().parent_node = None;
                }
                bubble_up = None;
            } else {
                let parent_weak = node.borrow().parent_node.as_ref().unwrap().clone();
                if let Some(parent_node) = parent_weak.upgrade() {
                    let mut parent_b = parent_node.borrow_mut();
                    if parent_b.left_child_node.as_ref().map_or(false, |n| Rc::ptr_eq(n, node)) {
                        parent_b.left_child_node = candidate.clone();
                        parent_b.left_child_count = candidate_count;
                    } else {
                        parent_b.right_child_node = candidate.clone();
                        parent_b.right_child_count = candidate_count;
                    }
                    drop(parent_b);
                    if let Some(ref c) = candidate {
                        c.borrow_mut().parent_node = Some(parent_weak);
                    }
                    bubble_up = Some(parent_node);
                } else {
                    bubble_up = None;
                }
            }
        }

        let mut current_bubble = bubble_up;
        let mut bubbling_finished = false;

        while let Some(ref bubble) = current_bubble {
            if !bubbling_finished {
                let left_depth = bubble.borrow().left_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
                let right_depth = bubble.borrow().right_child_node.as_ref().map_or(0, |n| n.borrow().depth + 1);
