                let depth_changed = new_depth != bubble.borrow().depth;
                bubble.borrow_mut().depth = new_depth;

                let balance = bostree_balance(&bubble.borrow());
                if balance < -1 {
                    let left = bubble.borrow().left_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&left.borrow()) > 0 {
                        rotate_left(self, &left);
                    }
                    let _ = rotate_right(self, bubble);
                } else if balance > 1 {
                    let right = bubble.borrow().right_child_node.as_ref().unwrap().clone();
                    if bostree_balance(&right.borrow()) < 0 {
                        rotate_right(self, &right);
                    }
                    let _ = rotate_left(self, bubble);
